// // This module selects an output from a 4-bit input array 'a' based on a 2-bit selector 'sel'. The output is determined as follows: when 'sel' is 00, the output is 'a[3]'; when 'sel' is 01, the output is 'a[2]'; when 'sel' is 10, the output is 'a[1]'; and when 'sel' is 11, the output is 'a[0]'.
module top_module (
    input [3:0] a,
    input [1:0] sel,
    output reg out);always @(*)
    case (sel)
        2'b00: out = a[0];
        2'b01: out = a[1];
        2'b10: out = a[2];
        2'b11: out = a[3];
    endcase

endmodule
